rules.constraint:
# Волна-с должна двигаться дальше конечной точки волны-а
# Для бычьего зигзага (направление вверх): конец волны-с выше конца волны-а
# Для медвежьего зигзага (направление вниз): конец волны-с ниже конца волны-а

if direction == 'up':
    end(wave_c) > end(wave_a)
elif direction == 'down':
    end(wave_c) < end(wave_a)

emulation_signs = {no_alternation_W2_W4, channel_mismatch,
  trendline_2_4_not_broken_fast, looks_impulsive_but_fails_rules} ;
IF count(emulation_signs) >= 2 THEN suspect_complex_correction_with_x_waves ; most_prone: complex_corrective_polywave → x_wave_missing ; ext1_impulse: W4_may_be_missing ; ext5_impulse: W2_may_be_missing
